<div class="card content-card mb-4"><div class="card-body p-4"><form method="get" action="<?= e(url('/reports/exits')); ?>" class="row g-3 align-items-end"><div class="col-lg-4"><label class="form-label">Search</label><input type="text" name="q" class="form-control" placeholder="Employee, department, or reason..." value="<?= e((string) ($search ?? '')); ?>"></div><div class="col-md-4 col-lg-2"><label class="form-label">Status</label><select name="status" class="form-select"><option value="all">All statuses</option><?php foreach (['draft' => 'Draft', 'pending' => 'Pending', 'in_progress' => 'In Progress', 'completed' => 'Completed', 'cancelled' => 'Cancelled'] as $value => $label): ?><option value="<?= e($value); ?>" <?= (string) ($status ?? 'all') === $value ? 'selected' : ''; ?>><?= e($label); ?></option><?php endforeach; ?></select></div><div class="col-md-4 col-lg-2"><label class="form-label">Type</label><select name="record_type" class="form-select"><option value="all">All types</option><?php foreach (['resignation' => 'Resignation', 'termination' => 'Termination', 'retirement' => 'Retirement', 'contract_end' => 'Contract End', 'absconding' => 'Absconding', 'other' => 'Other'] as $value => $label): ?><option value="<?= e($value); ?>" <?= (string) ($recordType ?? 'all') === $value ? 'selected' : ''; ?>><?= e($label); ?></option><?php endforeach; ?></select></div><div class="col-md-3 col-lg-2"><label class="form-label">From</label><input type="date" name="from_date" class="form-control" value="<?= e((string) ($fromDate ?? '')); ?>"></div><div class="col-md-3 col-lg-2"><label class="form-label">To</label><input type="date" name="to_date" class="form-control" value="<?= e((string) ($toDate ?? '')); ?>"></div><div class="col-12 d-flex gap-2"><button type="submit" class="btn btn-outline-secondary">Filter</button><a href="<?= e(url('/reports/exits')); ?>" class="btn btn-outline-light border">Reset</a><span class="text-muted small align-self-center ms-auto"><?= e((string) ($scopeLabel ?? '')); ?></span></div></form></div></div>

<div class="card content-card"><div class="card-body p-4"><div class="d-flex justify-content-between align-items-center mb-3"><h5 class="mb-0">Exit Records</h5><span class="badge text-bg-light border"><?= e((string) count($records ?? [])); ?> record(s)</span></div><?php if (($records ?? []) === []): ?><div class="empty-state">No offboarding records matched the selected filters.</div><?php else: ?><div class="table-responsive"><table class="table align-middle mb-0"><thead><tr><th>Employee</th><th>Type</th><th>Exit Date</th><th>Status</th><th>Clearance</th><th>Reason</th></tr></thead><tbody><?php foreach ($records as $row): ?><tr><td><div class="fw-semibold"><?= e((string) $row['employee_name']); ?></div><div class="small text-muted"><?= e((string) $row['employee_code']); ?> · <?= e((string) $row['department_name']); ?></div></td><td><?= e(ucwords(str_replace('_', ' ', (string) $row['record_type']))); ?></td><td><div><?= e((string) $row['exit_date']); ?></div><div class="small text-muted">Last day: <?= e((string) (($row['last_working_date'] ?? null) !== null ? $row['last_working_date'] : '—')); ?></div></td><td><span class="badge text-bg-light border"><?= e(ucwords(str_replace('_', ' ', (string) $row['status']))); ?></span></td><td><?= e(ucwords(str_replace('_', ' ', (string) $row['clearance_status']))); ?></td><td><?= e((string) (($row['reason'] ?? null) !== null && $row['reason'] !== '' ? $row['reason'] : '—')); ?></td></tr><?php endforeach; ?></tbody></table></div><?php endif; ?></div></div>